sql:
SELECT hub_name
FROM hubs
WHERE hub_status = 'active';

SELECT COUNT(*) AS active_hub_count
FROM hubs
WHERE hub_status = 'active';

external_knowledge:
- "Turbulent hubs" refers to those with high annualized volatility; 
- "Hazardous hubs" refers to those with high value at risk; 
- "Sailing through stormy waters" is a metaphor for hubs having a high level of volatility; 
- "Navigating high risks" refers to hubs with a high value at risk; 
- "Failing to meet regulatory standards" refers to hubs with a non-compliant status; 
- "Bustling with intense trading activity" refers to hubs with more than 50 trades.
